def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def solve_with_checks(nums, target):
    if not nums or len(nums) < 2:
        return -1, -1  # Handle no-solution case

    left, right = 0, len(nums) - 1
    seen_indices = set()  # To ensure indices are not reused
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            if left not in seen_indices and right not in seen_indices:
                seen_indices.add(left)
                seen_indices.add(right)
                return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1
